export function nextGeneration(cells: Cell[]): Cell[] {
  const key = (c: Cell) => `${c[0]},${c[1]}`;
  const liveSet = new Set(cells.map(key));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const k = `${nx},${ny}`;
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const next: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    const [xs, ys] = k.split(",");
    const cell: Cell = [Number(xs), Number(ys)];
    const alive = liveSet.has(k);
    if (alive && (count === 2 || count === 3)) next.push(cell);
    else if (!alive && count === 3) next.push(cell);
  }

  return next;
}

